namespace YourNamespace.Models;

public enum OrderStatus
{
    Pending,
    Processing,
    Shipped,
    Delivered,
    Cancelled
}

using System.ComponentModel.DataAnnotations;

namespace YourNamespace.Models;

/// <summary>Represents an order returned by the API.</summary>
public sealed record OrderResponse(
    int Id,
    int CustomerId,
    DateTimeOffset PlacedAt,
    decimal TotalAmount,
    OrderStatus Status);

/// <summary>Payload for creating a new order.</summary>
public sealed record CreateOrderRequest
{
    [Required]
    public required int CustomerId { get; init; }

    [Required]
    public required DateTimeOffset PlacedAt { get; init; }

    [Range(0.01, double.MaxValue)]
    public required decimal TotalAmount { get; init; }

    [Required]
    public required OrderStatus Status { get; init; }
}

using YourNamespace.Models;

namespace YourNamespace.Services;

public interface IOrderService
{
    Task<IReadOnlyList<OrderResponse>> GetAllAsync(CancellationToken cancellationToken);
    Task<OrderResponse?> GetByIdAsync(int id, CancellationToken cancellationToken);
    Task<OrderResponse> CreateAsync(CreateOrderRequest request, CancellationToken cancellationToken);
}

using Microsoft.AspNetCore.Mvc;
using YourNamespace.Models;
using YourNamespace.Services;

namespace YourNamespace.Controllers;

[ApiController]
[Route("api/[controller]")]
public class OrdersController : ControllerBase
{
    private readonly IOrderService _service;

    public OrdersController(IOrderService service)
    {
        _service = service;
    }

    /// <summary>Get all orders.</summary>
    [HttpGet]
    [ProducesResponseType(typeof(List<OrderResponse>), StatusCodes.Status200OK)]
    public async Task<ActionResult<List<OrderResponse>>> GetAll(CancellationToken cancellationToken)
    {
        var orders = await _service.GetAllAsync(cancellationToken);
        return Ok(orders);
    }

    /// <summary>Get an order by ID.</summary>
    [HttpGet("{id}")]
    [ProducesResponseType(typeof(OrderResponse), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    public async Task<ActionResult<OrderResponse>> GetById(int id, CancellationToken cancellationToken)
    {
        var order = await _service.GetByIdAsync(id, cancellationToken);
        return order is null ? NotFound() : Ok(order);
    }

    /// <summary>Create a new order.</summary>
    [HttpPost]
    [ProducesResponseType(typeof(OrderResponse), StatusCodes.Status201Created)]
    [ProducesResponseType(StatusCodes.Status400BadRequest)]
    public async Task<ActionResult<OrderResponse>> Create(
        CreateOrderRequest request, CancellationToken cancellationToken)
    {
        var created = await _service.CreateAsync(request, cancellationToken);
        return CreatedAtAction(nameof(GetById), new { id = created.Id }, created);
    }
}

